% --- Test Points ---
Q = [ 0.720019811451439   0.3699052448260266  0.549525179318315  ; %A
      0.23077010741445197 0.50706960509276455 0.59843671108690721; %B
      1.119120364165727   0.5749411870878969 -0.1470160478395422 ; %C
      0.624050411792      0.877724440703      0.132061250873     ; %D
      0                   1                   0                  ; %E
      0.223391079094      0.086837135163      0.695524091907     ; %F
      1.38330953120054    0.2079119295392694  0                  ; %G
      sqrt(2)             0                   0                  ; %H
      0                   -0.8386706670106496 0.3851178470911804 ];%I

S = zeros(size(Q,1),1);
W = zeros(size(Q,1),1);
B = cell(size(Q,1),1);
C = zeros(size(Q,1),size(G_poly,1));
fmt = 'S[table-format=1.6]';

fprintf('\\begin{table}[!hbtp]\n')
fprintf('\\setlength{\\fboxsep}{1pt} %% Sets smaller spacing\n')
fprintf('\\centering\n')
fprintf('  \\begin{tabular}{c%s%s%s|l|rcl|l}\n',fmt,fmt,fmt);
fprintf('  Query & \\multicolumn{3}{c|}{Coordinates}\n')
fprintf('        & PiGEP & \\multicolumn{3}{c|}{Crossing Numbers}            & PiGP    \\\\\n')
fprintf('  Point & {$x$} & {$y$} & {$z$} & Results & PiP/PiGEP & & PiGP & Results \\\\\\hline\n')
for i = 1:size(Q,1)
      [S(i),W(i),B{i},C(i,:)] = pisp4bae(Q(i,:),G_poly',true);
      % Column 1: Name of Query point
      qname = char('A'+(i-1));
      % Columns 2-4:
      x = Q(i,1);
      y = Q(i,2);
      z = Q(i,3);
      % Column 5: PiGEP result
      switch mod(i-1,3)
            case 0
                  pigep = ['$' qname '\in\interior{G}$'];
            case 1
                  pigep = ['$' qname '\in\partial{G}$ '];
            case 2
                  pigep = ['$' qname '\in\exterior{G}$'];
      end
      fprintf('    $%c$ & % 1.6f & % 1.6f & % 1.6f & %s \n',qname,x,y,z,pigep)
      % Column 6: PiP Crossings with CN marked for updates
      crossings = arrayfun(@num2str,C(i,:),'UniformOutput',false);
      crossings(isnan(C(i,:))) = {'\infty'};
      %  Necessary Conditions to be in the EBBox? (do not apply quadratic asymptotes to each edge)
      in_ebbox = false(1,size(C,2));
      for j = 1:size(C,2)
            % If edge is great elliptic, no correction is needed
            if G_ge(j)
                  continue
            end
            % If Q is outside the lune, no correction is needed
            Vp = G_poly(j,:);
            Vn = G_poly(mod(j,size(G_poly,1))+1,:);
            P = cross(Vp,Vn);
            nA = cross(P,Vp);
            nB = cross(Vn,P);
            if dot(nA,Q(i,:))<0||dot(nB,Q(i,:))<0
                  continue
            end
            % Compute the max lateral geodesic deviation
            [~,L] = gealen(Vp,Vn,a,b,c,200);
            hL2 = Ke*L^2;
            % If the normal distance is within bounds, perform correction
            nP = normalize(cross(Vp,Vn),'norm');
            if abs(dot(nP,Q(i,:)))<=hL2
                  in_ebbox(j) = true;
            end
      end
      for ind_ebbox = find(in_ebbox)
            crossings{ind_ebbox} = sprintf('{\\color{red}\\boxed{%s}}',crossings{ind_ebbox});
      end
      fprintf('        & $(%37s)$ ', join(string(crossings),','));
      % Column 7--8: Updated crossing number
      fprintf(' & ')
      for ind_ebbox = find(in_ebbox)
            [~,~,~,cn] = pisp4bae(Q(i,:)',G_edge{ind_ebbox}',true);
            alpha = sum(cn(1:end-1));
            if isnan(alpha)
                  cn_str = '\infty';
            else
                  cn_str = num2str(alpha);
            end
            crossings{ind_ebbox} = sprintf('{\\color{red}\\boxed{%s}}',cn_str);
      end
      if any(in_ebbox)
            fprintf('$\\mapsto$ & $(%17s)$ ', join(string(crossings),','))
      else
            fprintf('          &                     ')
      end
      % Column 9: PiGP result
      % While the new crossing numbers and the antipode discrimination test are required,
      % these specific cases yield predetermined results by design.
      switch floor((i-1)/3)
            case 0
                  pigp = ['$' qname '\in\interior\mathcal{G}$'];
            case 1
                  pigp = ['$' qname '\in\partial\mathcal{G}$ '];
            case 2
                  pigp = ['$' qname '\in\exterior\mathcal{G}$'];
      end
      fprintf(' & %s',pigp);
      % Newline
      if i < size(Q,1)
            fprintf(' \\\\\n')
      else
            fprintf('\n')
      end
end
fprintf('  \\end{tabular}\n')
fprintf('  \\caption{Query points}\n')
fprintf('  \\label{table:q}\n')
fprintf('\\end{table}\n')
